var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"네? 그게 무슨......","JPN":"はい？　それってどういう……","ENG":"Sorry? What do you mean?","TWN":"咦？您是說……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"애가 울고불고하는 바람에 부모가 찾아와서 웃돈을 물어줘도 데려가야겠대.","JPN":"娘に泣きつかれたらしくてな。両親は違約金を上乗せしてでも連れ戻すと言っているんだ。","ENG":"The kid cried so much that her parents insisted that they'd take her back, even when we offered to pay more.","TWN":"因為那孩子又哭又鬧的，所以她的父母說就算要額外付錢，也要把她帶走。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"달래고 달래서 당분간 요양만 하고 돌아온다고 약속을 받긴 했는데......","JPN":"何とかなだめて、しばらく療養したら\\n復帰してもらう約束はしてもらったが……","ENG":"I managed to persuade them to promise to bring her back after she gets some rest...","TWN":"我安撫了他們好一會，然後答應孩子養好病後，就會讓她回去……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"......솔직히 내 생각에도 자네의 스케쥴은 과한 감이 없지 않아.","JPN":"……正直、私から見ても、君が立てるスケジュールは過剰気味だ。","ENG":"But honestly, even I think you're working those girls too hard.","TWN":"……說實話，我也覺得妳的行程安排有點太超過了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"아이돌이잖아요? 그 아이는 제게 최고가 되고 싶다고 했어요. 그럼 그 정도는 감수하는 게 당연한 거죠.","JPN":"アイドルなんでしょう？　あの子は\\nトップに立ちたいと私に言ったんです。\\nなら、その程度の苦労は覚悟の上のはずです。","ENG":"But they're super stars. She told me she wanted to become the best. She should know that's what it takes.","TWN":"她不是偶像嗎？那孩子跟我說過要成為最棒的偶像。那麼這種程度是理所當然的吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"그게...... 아무리 아이돌이라고는 해도 아직 어리지 않나. 이런 일정을 밀어붙였다간 부모가 또 항의를 해올 거라고.","JPN":"しかし……いくらアイドルと言ってもまだ子供だからな。\\nこんなスケジュールだと、また保護者から抗議が来るぞ。","ENG":"Well... Even so, she's just a kid. If we keep forcing this kind of schedule on her, her parents will come complaining again.","TWN":"這……就算是偶像，但她還是個小孩啊。繼續安排這種行程的話，她父母又會過來抗議的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"그 애 집안 어른들이 우리 회사에 얼마나 많은 도움을 줬는진...... 자네도 잘 알지 않나?","JPN":"あの子に我が社がどれだけ助けられてきたか……君も重々承知のはずだろう？","ENG":"I don't need to tell you how much her family's been able to help our company, do I?","TWN":"那孩子的家裡為我們公司提供了多少幫助……妳不是很清楚嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"대표님. 저는 제가 해야 할 일을 하고 있는 것뿐이에요. 물론 사정을 봐주면서 스케쥴을 조정할 수도 있겠죠.","JPN":"代表。私は自分の務めを果たしているだけです。\\nもちろん、事情を汲んでスケジュールを調整することも可能です。","ENG":"Sir. I'm just doing my job. Of course, we could adjust their schedule if needed.","TWN":"代表。我只是做我該做的事情而已。當然，要我視情況調整行程也是可以的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"하지만, 그 배려 때문에 그 애가 원하는 꿈을 이루지 못한다면...... 전 제 스스로를 책망할 수 밖에 없을 거에요.","JPN":"しかし、その配慮によって彼女の夢が叶わなくなってしまったら……\\n私は自分を責めずにはいられないでしょう。","ENG":"But if that sort of pampering prevents her from fulfilling her dream, I'll only have myself to blame.","TWN":"但是如果因為擔心這種事，使那孩子夢想的無法實現……那我就只能責備我自己了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"다 맞는 말이야. 하지만 어쩔 텐가? 아이돌이라고 해도 결국 세상물정 모르는 애들이잖나.","JPN":"君の言ってる事は正しい。\\nしかし現実はどうだ？　彼女達はアイドルである前に、世間の厳しさを知らない子供だ。","ENG":"You're completely right about what you said. But what choice do we have? Stars or not, they're just innocent kids at the end of the day.","TWN":"話是這麼說沒錯。但妳能怎麼辦？就算是偶像，她終究是個不懂人情世故的孩子啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"아이돌이 철인은 아냐. 채찍질만 해서는 정신이 버티질 못한다고.","JPN":"アイドルではあっても、アスリートではないはずだ。\\n鞭を打ってばかりでは心が持たないだろう。","ENG":"They're pop stars, not superheroes. You can't expect them to last with just stern discipline.","TWN":"偶像不是什麼鐵人。如果只是一直鞭策她，她會撐不下去的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"......그렇다면 저는 저만의 철인 그룹을 만들어야겠네요.","JPN":"……なら私は私なりに、アスリートのグループを作るしかなさそうですね。","ENG":"Then I'll have to assemble my own group of superheroes.","TWN":"……既然如此，那我就組一個屬於我的鐵人團體。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"응? 그게 무슨 소린가.","JPN":"む？　それはどういうことだ？","ENG":"Hm? What are you talking about?","TWN":"什麼？這是什麼意思啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"대표님. 저도 이 일에 자부심이 있고, 여기서 청춘을 바치고 있어요.","JPN":"代表。私はこの仕事に誇りを\\n持っており、自らの青春を捧げてきました。","ENG":"Boss. I take great pride in this work, and I've been very committed to this company.","TWN":"代表。我為自己的工作感到自豪，為這裡奉獻著我的青春。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"하지만 언제까지고 지금처럼 일할 수 있는 게 아니죠.","JPN":"ですが、いつまでも\\n今まで通りというわけにはいきません。","ENG":"But I won't be able to work like this forever.","TWN":"但我不想一直維持現狀。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"전...... 이 시기가 지나기 전에 최고의 아이돌 그룹을 제 손으로 빚어내 보고 싶어요.","JPN":"私は……時機を逸する前に、\\n最高のアイドルグループを自らの手で作り上げたいと思っています。","ENG":"You see, I want to create my very own girl group before it's too late. The best of the best.","TWN":"我……我想趁這個時代過去之前，親手打造一個最棒的偶像團體。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"아니 잠깐, 지금 그 말은 설마......","JPN":"まさか君、それはつまり……","ENG":"Hang on, are you saying...","TWN":"不，等等，妳這樣說該不會是……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"다른 기획사로 이직이라도 하겠다는 소리야?","JPN":"他の事務所に移るとでも言うのかね？","ENG":"You're going to move to another agency or something?","TWN":"想跳槽到別的企劃公司吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"아뇨, 저는 저만의 회사를 차리겠어요.","JPN":"いいえ、私は私の会社を立ち上げます。","ENG":"No, I'll set up my own company.","TWN":"不，我要開一家只屬於我的公司。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그리고 제가 대표로서 직접 아이돌을 매니지먼트 할 겁니다.","JPN":"そして、私が代表となり\\n自らアイドルをマネジメントするつもりです。","ENG":"And I'll manage the talent myself as the primary agent.","TWN":"並且作為代表，直接管理偶像。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"앞으로 한 달. 그 동안 차기 매니저한테 제 모든 역할을 인수인계하고, 저는 여길 떠나겠어요.","JPN":"一か月です。一か月の間に次のマネージャーへの引継ぎを完了し、私はここを離れます。","ENG":"I'll stick around for one more month. I'll make sure my replacement is up to speed with my current role. And then I'll leave.","TWN":"接下來一個月，我會把所有工作都轉交給下一任經紀人，然後離開這裡。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"허허, 회사를 자네가 운영한다고? 그런 게 말처럼 쉽게 가능할 거라고 생각하나?","JPN":"ハッ、君が会社を運営するだと？　言うほど簡単なことではないぞ？","ENG":"Ha, you're going to run a company? Do you think it's really that easy?","TWN":"哈哈，妳來經營公司嗎？妳以為這種事跟說的一樣簡單嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"아이돌은 누구나 할 수 있지만, 일류라는 건 패기나 열정만 가지고 될 수 있는 게 아니야.","JPN":"アイドル自体は誰でもできるが、一流になるということは、情熱や覇気だけではどうにもならないのだよ。","ENG":"Anyone can be a star, but you can't become the best with just determination and passion.","TWN":"偶像誰都當得了，但是要成為一流偶像，可不是光靠氣勢和熱情就能辦到的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"두고 보시죠. 조만간 명함 보내드릴게요.","JPN":"どうにかなるところをご覧に\\n入れましょう。近いうちに名刺をお送りしますね。","ENG":"You'll see. I'll send you my new business card soon.","TWN":"您等著瞧吧，我這陣子會給您我的名片的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CEO_EXTRA_NULL_NULL","text":{"KOREA":"최 매니저! 잠깐만!","JPN":"待ちたまえ！　ハラジマ君！","ENG":"Manager Choi! Wait!","TWN":"崔經紀人！等一下啊！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"}]`);export{e as default};